import json
import re
from pathlib import Path

RETRYABLE = {429, 500, 503}

def analyze(paths):
    report = {'retryable_events': 0, 'non_retryable_error_events': 0}
    for source in sorted(paths):
        for match in re.finditer(r'status=(\d+)', source.read_text()):
            status = int(match.group(1))
            if status in RETRYABLE:
                report['retryable_events'] += 1
            elif status >= 400:
                report['non_retryable_error_events'] += 1
    return report

def main():
    report = analyze(Path('logs').glob('*.log'))
    Path('incident_report.json').write_text(json.dumps(report, indent=2) + '\n')

if __name__ == '__main__':
    main()

