class Client:
    def request(self, method, path, payload=None, *, headers=None):
        return {
            'transport': 'sync',
            'method': method,
            'path': path,
            'payload': payload,
            'headers': dict(headers or {}),
        }

    async def request_async(self, method, path, payload=None):
        return {
            'transport': 'async',
            'method': method,
            'path': path,
            'payload': payload,
        }

    def request_batch(self, method, path, items):
        values = list(items)
        return {
            'transport': 'batch',
            'method': method,
            'path': path,
            'items': values,
            'count': len(values),
        }

    def request_stream(self, method, path, items):
        for index, item in enumerate(items):
            yield {
                'transport': 'stream',
                'method': method,
                'path': path,
                'item': item,
                'index': index,
            }

