import asyncio
import json
import unittest
from pathlib import Path

from packages import (
    a_create, a_update, b_create, b_update,
    c_delete, c_lookup, d_delete, d_lookup,
    e_bulk_create, e_bulk_update, f_bulk_archive, f_bulk_publish,
    g_audit, g_stream, h_audit, h_stream,
)
from src.sdk.client import Client

ADAPTERS = [
    'packages/a_create.py', 'packages/a_update.py',
    'packages/b_create.py', 'packages/b_update.py',
    'packages/c_lookup.py', 'packages/c_delete.py',
    'packages/d_lookup.py', 'packages/d_delete.py',
    'packages/e_bulk_create.py', 'packages/e_bulk_update.py',
    'packages/f_bulk_publish.py', 'packages/f_bulk_archive.py',
    'packages/g_stream.py', 'packages/g_audit.py',
    'packages/h_stream.py', 'packages/h_audit.py',
]
PARTITIONS = ['packages-ab', 'packages-cd', 'packages-ef', 'packages-gh']

class MigrationTests(unittest.TestCase):
    def sync_result(self, method, path, payload, headers=None):
        return {'transport': 'sync', 'method': method, 'path': path, 'payload': payload, 'headers': headers or {}}

    def async_result(self, method, path, payload=None):
        return {'transport': 'async', 'method': method, 'path': path, 'payload': payload}

    def batch_result(self, method, path, items):
        return {'transport': 'batch', 'method': method, 'path': path, 'items': items, 'count': len(items)}

    def test_packages_ab_sync_create_and_update(self):
        client = Client()
        payload = {'name': 'alpha'}
        changes = {'enabled': True}
        self.assertEqual(a_create.create(client, payload), self.sync_result('POST', '/a/items', payload))
        self.assertEqual(a_update.update(client, 'a-7', changes), self.sync_result('PATCH', '/a/items/a-7', changes))
        self.assertEqual(b_create.create(client, payload), self.sync_result('POST', '/b/records', payload))
        self.assertEqual(b_update.update(client, 'b-3', changes), self.sync_result('PUT', '/b/records/b-3', changes))

    def test_packages_cd_async_lookup_and_delete(self):
        client = Client()
        self.assertEqual(asyncio.run(c_lookup.lookup(client, 'c-1')), self.async_result('GET', '/c/items/c-1'))
        self.assertEqual(asyncio.run(c_delete.delete(client, 'c-2')), self.async_result('DELETE', '/c/items/c-2'))
        self.assertEqual(asyncio.run(d_lookup.lookup(client, 'd-1')), self.async_result('GET', '/d/records/d-1'))
        self.assertEqual(asyncio.run(d_delete.delete(client, 'd-2', hard=True)), self.async_result('DELETE', '/d/records/d-2', {'hard': True}))

    def test_packages_ef_batch_operations(self):
        client = Client()
        rows = [{'id': 1}, {'id': 2}]
        identifiers = ['f-1', 'f-2']
        self.assertEqual(e_bulk_create.bulk_create(client, rows), self.batch_result('POST', '/e/items', rows))
        self.assertEqual(e_bulk_update.bulk_update(client, rows), self.batch_result('PATCH', '/e/items', rows))
        self.assertEqual(f_bulk_publish.bulk_publish(client, rows), self.batch_result('POST', '/f/publish', rows))
        self.assertEqual(f_bulk_archive.bulk_archive(client, identifiers), self.batch_result('DELETE', '/f/archive', identifiers))

    def test_packages_gh_streaming_and_audit(self):
        client = Client()
        events = [{'event': 'opened'}, {'event': 'closed'}]
        expected = [
            {'transport': 'stream', 'method': 'POST', 'path': '/g/events', 'item': event, 'index': index}
            for index, event in enumerate(events)
        ]
        self.assertEqual(list(g_stream.stream_events(client, events)), expected)
        chunks = ['one', 'two']
        expected = [
            {'transport': 'stream', 'method': 'PUT', 'path': '/h/snapshots', 'item': chunk, 'index': index}
            for index, chunk in enumerate(chunks)
        ]
        self.assertEqual(list(h_stream.stream_snapshots(client, chunks)), expected)
        self.assertEqual(
            g_audit.record_audit(client, 'luiz', {'event': 'deploy'}),
            self.sync_result('POST', '/g/audit', {'event': 'deploy'}, {'X-Audit-Actor': 'luiz'}),
        )
        self.assertEqual(
            h_audit.record_audit(client, 'luiz', 'archive', 'h-9'),
            self.sync_result('POST', '/h/audit', {'action': 'archive', 'subject': 'h-9'}, {'X-Audit-Actor': 'luiz'}),
        )

    def test_report_is_complete(self):
        report = json.loads(Path('migration_report.json').read_text())
        self.assertEqual(report, {'migrated_adapters': ADAPTERS, 'partitions': PARTITIONS, 'shared_api': 'request-family'})

    def test_no_compatibility_send_methods(self):
        client = Client()
        for name in ('send', 'send_async', 'send_batch', 'send_stream', 'send_audit'):
            with self.subTest(name=name):
                self.assertFalse(hasattr(client, name))

