import json
from pathlib import Path

policy = json.loads(Path('credit_policy.json').read_text())

def decide(ticket):
    if not ticket['account_active']:
        return 0, 'inactive'
    if not ticket['evidence_verified']:
        return 0, 'unverified'
    if ticket['category'] == 'duplicate_billing':
        return min(ticket['overcharge'], policy['duplicate_billing_cap']), 'duplicate_billing'
    if ticket['category'] == 'outage':
        if ticket['plan'] == 'premium' and ticket['minutes'] >= policy['outage_premium_min_minutes']:
            return policy['outage_premium_credit'], 'outage_120_premium'
        if ticket['minutes'] >= policy['outage_standard_min_minutes']:
            return policy['outage_standard_credit'], 'outage_60'
    return 0, 'ineligible'

decisions = []
for source in sorted(Path('tickets').glob('*.json')):
    ticket = json.loads(source.read_text())
    credit, reason = decide(ticket)
    decisions.append({'ticket_id': ticket['ticket_id'], 'credit': credit, 'reason': reason})
report = {
    'awarded_count': sum(item['credit'] > 0 for item in decisions),
    'total_credit': sum(item['credit'] for item in decisions),
    'decisions': decisions,
}
out = Path('out')
out.mkdir(exist_ok=True)
(out / 'credits.json').write_text(json.dumps(report, indent=2) + '\n')
(out / 'audit.md').write_text(f"# Credit adjudication\n\nAwarded tickets: {report['awarded_count']}\n\nTotal credit: {report['total_credit']}\n")

